function PetLog() {
  const [logs, setLogs] = React.useState([
    { pet: 'Baxter', activity: 'Walk', time: new Date(Date.now() - 2 * 3600000).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) },
    { pet: 'Luna', activity: 'Fed', time: new Date(Date.now() - 5 * 3600000).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) },
    { pet: 'Baxter', activity: 'Fed', time: new Date(Date.now() - 8 * 3600000).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) }
  ]);
  const [pet, setPet] = React.useState('');
  const [activity, setActivity] = React.useState('Walk');
  const activities = ['Walk', 'Fed', 'Play', 'Groom', 'Vet', 'Medicine'];

  function addLog() {
    if (!pet.trim()) return;
    const time = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    setLogs([{ pet, activity, time }, ...logs]);
    setPet('');
  }

  function removeLog(idx) {
    setLogs(logs.filter((_, i) => i !== idx));
  }

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#fff', borderRadius: 12, height: '100%', boxSizing: 'border-box', display: 'flex', flexDirection: 'column' }}>
      <h2 style={{ margin: '0 0 12px 0', fontSize: 18, color: '#1a1a1a' }}>Pet Log</h2>
      <div style={{ display: 'flex', gap: 8, marginBottom: 12 }}>
        <input placeholder="Pet name" value={pet} onChange={e => setPet(e.target.value)} style={{ flex: 1, padding: '6px 10px', borderRadius: 6, border: '1px solid #ddd', fontSize: 13 }} />
        <select value={activity} onChange={e => setActivity(e.target.value)} style={{ padding: '6px 10px', borderRadius: 6, border: '1px solid #ddd', fontSize: 13, background: '#fff' }}>
          {activities.map(a => <option key={a} value={a}>{a}</option>)}
        </select>
        <button onClick={addLog} style={{ padding: '6px 14px', borderRadius: 6, border: 'none', background: '#f59e0b', color: '#fff', fontSize: 13, cursor: 'pointer' }}>Log</button>
      </div>
      <div style={{ flex: 1, overflowY: 'auto' }}>
        {logs.map((log, i) => (
          <div key={i} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '10px 12px', borderRadius: 8, background: '#f8f9fa', marginBottom: 8 }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
              <span style={{ fontSize: 20 }}>{log.activity === 'Walk' ? '\ud83c\udfc3' : log.activity === 'Fed' ? '\ud83c\udf7d\ufe0f' : log.activity === 'Play' ? '\ud83c\udfae' : log.activity === 'Groom' ? '\u2702\ufe0f' : log.activity === 'Vet' ? '\ud83d\udc8a' : '\ud83d\udc31'}</span>
              <div>
                <div style={{ fontWeight: 600, fontSize: 14, color: '#1a1a1a' }}>{log.pet}</div>
                <div style={{ fontSize: 12, color: '#666' }}>{log.activity}</div>
              </div>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
              <span style={{ fontSize: 12, color: '#888' }}>{log.time}</span>
              <button onClick={() => removeLog(i)} style={{ background: 'transparent', border: 'none', color: '#999', cursor: 'pointer', fontSize: 14 }}>x</button>
            </div>
          </div>
        ))}
        {logs.length === 0 && <div style={{ textAlign: 'center', color: '#999', fontSize: 13, padding: 20 }}>No logs yet. Add one above!</div>}
      </div>
    </div>
  );
}
render(<PetLog/>);
